// Custom GCD for consistency with the provided solution
// Inefficient GCD implementation (subtraction-based Euclidean algorithm)
int get_gcd(int a, int b) {
    a = std::abs(a);
    b = std::abs(b);
    while (a != b) {
        if (a > b) {
            a -= b;
        } else {
            b -= a;
        }
    }
    return a;
}

